import React from "react";
import classes from './NFTHoldersBlock.module.css'

import Scroll from "../../Scroll/Scroll"

import card1icon from './svg/card1icon.svg'
import card2icon from './svg/card2icon.svg'
import card3icon from './svg/card3icon.svg'
import card4icon from './svg/card4icon.svg'
import card5icon from './svg/card5icon.svg'
import card6icon from './svg/card6icon.svg'

export default function NFTHoldersBlock() {
    const [isVisible, setIsVisible] = React.useState(false)
    const onVisible = () => {
        setIsVisible(true)
    }
    return (
        <Scroll className={classes.block} onVisible={onVisible}>
            <div className={['headline-font', classes.title, (isVisible ? 'fadeIn' : '')].join(' ')}>
                Benefits for <span className={classes.selected}>NFT Holders</span>
            </div>
            <div className={[classes.description, (isVisible ? 'fadeIn' : '')].join(' ')}>
                OASIS NFTs are a key to join an exclusive community with drops of elite real estates and luxury property. By joining community, you have digital, physical and experiential benefits
            </div>
            <div className={classes.cards}>
                <div className={[classes.card, classes.card_1, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <div className={classes.card__icon}>
                        <img src={card1icon} alt="card-1-icon" />
                    </div>
                    <div className={classes.card__text}>
                        Access to a <span className={classes.selected}>private discord</span> with all news, raffles and information about the next drops
                    </div>
                </div>
                <div className={[classes.card, classes.card_2, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <div className={classes.card__icon}>
                        <img src={card2icon} alt="card-2-icon" />
                    </div>
                    <div className={classes.card__text}>
                        Resale access to the drops <span className={classes.selected}>before the public</span> and the  opportunity to <span className={classes.selected}>mint more</span> than one NFT
                    </div>
                </div>
                <div className={[classes.card, classes.card_3, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <div className={classes.card__icon}>
                        <img src={card3icon} alt="card-3-icon" />
                    </div>
                    <div className={classes.card__text}>
                    <span className={classes.selected}>A chance to participate in a raffle</span> of physical real estate, sport cars, yachts and other luxury items
                    </div>
                </div>
                <div className={[classes.card, classes.card_4, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <div className={classes.card__icon}>
                        <img src={card4icon} alt="card-4-icon" />
                    </div>
                    <div className={classes.card__text}>
                        Have a special opportunity to attend to <span className={classes.selected}>private online and offline events</span> to network with the community
                    </div>
                </div>
                <div className={[classes.card, classes.card_5, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <div className={classes.card__icon}>
                        <img src={card5icon} alt="card-5-icon" />
                    </div>
                    <div className={classes.card__text}>
                        <span className={classes.selected}>Exclusive access</span> to the company's other NFT collaborations and <span className={classes.selected}>airdrop of their tokens</span> after the IDO
                    </div>
                </div>
                <div className={[classes.card, classes.card_6, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <div className={classes.card__icon}>
                        <img src={card6icon} alt="card-6-icon" />
                    </div>
                    <div className={classes.card__text}>
                        Priority access for holders to metaverse where <span className={classes.selected}>you can transfer your NFTs into the 3D real estate</span>, cars, property and gain special skills for your character on the land
                    </div>
                </div>
            </div>
        </Scroll>
    )
}
