import React from "react";
import { flushSync } from "react-dom";
import classes from './FAQ.module.css'

import Scroll from "../../Scroll/Scroll"

export default function FAQ() {
    let [question, setQuestion] = React.useState(-1)
    const [isVisible, setIsVisible] = React.useState(false)

    const onVisible = () => {
        setIsVisible(true)
    }

    const openQA = (q) => {
        if (question === q) {
            flushSync(() => setQuestion(-1))
            return
        }
        flushSync(() => setQuestion(q))
    }

    return (
        <Scroll className={classes.block} onVisible={onVisible}>
            <div className={['headline-font', classes.headline, (isVisible ? 'fadeIn' : '')].join(' ')}>FAQ</div>
            <div className={classes.qa_list}>
                <div className={[
                        classes.qa,
                        (question === 0 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(0)}>
                        What are the benefits for oasis holders?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>OASIS holders have access to a series of exclusive drops featuring both digital and physical estates. After the IDO the longer you hold NFT, the more tokens you get. </div>
                </div>
                <div className={[
                        classes.qa,
                        (question === 1 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(1)}>
                        is there a discord?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>Yes, but OASIS channels are closed. To  gain access to our discord, you should enable twitter and instagram notifications and follow  the news</div>
                </div>
                <div className={[
                        classes.qa,
                        (question === 2 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(2)}>
                        is there a guaranteed whitelist?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>Yes, but you’ll need to work hard in discord to have a whitelist</div>
                </div>
                <div className={[
                        classes.qa,
                        (question === 3 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(3)}>
                        How many oasis nfts will be in the collection?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>There will be 10 000 NFTs</div>
                </div>
                <div className={[
                        classes.qa,
                        (question === 4 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(4)}>
                        Are there any additional costs associated with membership?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>Gas is not included in the price</div>
                </div>
                <div className={[
                        classes.qa,
                        (question === 5 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(5)}>
                        what intellectual property rights do oasis holders receive?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>Owners of OASIS have full commercial art rights for the NFT they own. Full details coming soon (prior to launch).</div>
                </div>
                <div className={[
                        classes.qa,
                        (question === 6 ? classes.qa_opened : ''),
                        (isVisible ? 'fadeInUp' : '')
                    ].join(' ')}>
                    <div className={classes.question} onClick={() => openQA(6)}>
                        What chain will this collection be minted on?
                        <i className="fal fa-chevron-down" />
                    </div>
                    <div className={classes.answer}>OASIS NFTs will be minted  on OpenSea and traded on Ethereum Layer 1 mainnet.</div>
                </div>
            </div>
        </Scroll>
    )
}
