import React from "react";



export default function Scroll ({children, onVisible, onScrolling, onHide, className, POV, style, get}) {
    const divRef = React.useRef(null)
    const firstRender = React.useRef(true)
    const [pov] = React.useState(!!POV ? POV : 0.5)
    React.useEffect(()=>{
        if (firstRender.current) {
            if (divRef.current !== null) {
                if (typeof get !== `undefined`) {
                    get.current = divRef.current
                }
                firstRender.current = false
                let prev = 0
                document.addEventListener('scroll', (e) => {
                    if (typeof onScrolling === `function`) {
                        onScrolling({
                            prev,
                            current: window.scrollY,
                            direction: window.scrollY >= prev ? `down` : `up`
                        })
                    }
                    if (divRef.current !== null) {
                        let offsetTop = divRef.current.offsetTop+(divRef.current.offsetHeight*pov)
                        let currentOffsetTop = document.documentElement.scrollTop+(divRef.current.offsetHeight*pov)
                        if (document.documentElement.scrollTop > (divRef.current.offsetTop+divRef.current.offsetHeight) || currentOffsetTop < divRef.current.offsetTop) {
                            if (typeof onHide === `function`) {
                                onHide()
                                return
                            }
                        }
                        if ((offsetTop - currentOffsetTop) <= (divRef.current.offsetHeight/2)) {
                            if (typeof onVisible === `function`) {
                                onVisible()
                            }
                        }
                    }
                    prev = window.scrollY
                })
            }
        }
    }, [divRef])
    return (
        <div ref={divRef} className={className} style={style}>
            {children}
        </div>
    )
}
