import React from "react";
import classes from './CTFBlock.module.css'

import Scroll from "../../Scroll/Scroll"

import image_1 from './images/image_1.jpg'
import image_2 from './images/image_2.jpeg'
import image_3 from './images/image_3.jpeg'


export default function CTFBlock () {
    const [isVisible, setIsVisible] = React.useState(false)
    const onVisible = () => {
        setIsVisible(true)
    }
    return (
        <Scroll className={classes.block} onVisible={onVisible}>
            <div className={['headline-font', classes.title, (isVisible ? 'fadeIn' : '')].join(' ')}>
                Creating the future with <br />
                <span className={classes.selected}>the best of the best</span>
            </div>
            <div className={classes.partners}>
                <div className={[classes.partner, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <img alt="1" src={image_1} />
                </div>
                <div className={[classes.border_line, (isVisible ? 'fadeIn' : '')].join(' ')} />
                <div className={[classes.partner, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <img alt="2" src={image_2} />
                </div>
                <div className={[classes.border_line, (isVisible ? 'fadeIn' : '')].join(' ')} />
                <div className={[classes.partner, (isVisible ? 'fadeInUp' : '')].join(' ')}>
                    <img alt="3" src={image_3} />
                </div>
            </div>
        </Scroll>
    )
}
